	}
	else {
		first=p;
	}
	last=p;

}

void List::RemoveFront () {
	if (first!=NULL){
		Node* temp=first->next;
		if(first->next!=NULL){
		(first->next->prev)=NULL;
		}
		delete first;
		first=temp;
	}
}


void List::RemoveBack () {
	if (last!=NULL) {
		Node* temp=last->prev;
		if (last->prev!=NULL) {
			last->prev->next=NULL;
		}
		delete last;
		last=temp;
	}
}


